import{_ as i,o as e,c as o,ag as s}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"NOM","description":"","frontmatter":{},"headers":[],"relativePath":"es/standards/organizations/nom.md","filePath":"es/standards/organizations/nom.md"}'),n={name:"es/standards/organizations/nom.md"};function l(r,a,c,t,d,u){return e(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="nom" tabindex="-1">NOM <a class="header-anchor" href="#nom" aria-label="Permalink to &quot;NOM&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Las Normas Oficiales Mexicanas (NOM) son estándares obligatorios emitidos por el gobierno mexicano que establecen requisitos de seguridad, desempeño, etiquetado e instalación de productos y sistemas.</p><p>Estas normas definen el marco legal de cumplimiento en México y son aplicadas por autoridades regulatorias.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Las normas NOM se utilizan para:</p><ul><li>Garantizar la seguridad de las personas y la infraestructura</li><li>Definir requisitos técnicos e instalaciones obligatorias</li><li>Regular los productos que ingresan y se utilizan en México</li><li>Apoyar procesos de inspección, aprobación y cumplimiento legal</li><li>Alinear los requisitos nacionales con prácticas internacionales cuando aplica</li></ul><p>Son necesarias para que equipos y sistemas puedan ser instalados y operados legalmente en México.</p><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><p>Las normas NOM definen:</p><ul><li>Requisitos técnicos y criterios de desempeño</li><li>Reglas de seguridad y medidas de protección</li><li>Procedimientos de prueba y verificación</li><li>Requisitos de etiquetado y documentación</li></ul><p>El cumplimiento generalmente se verifica mediante:</p><ul><li>Laboratorios de prueba acreditados</li><li>Organismos de certificación autorizados en México</li><li>Marcados oficiales y documentación</li></ul><p>A diferencia de los estándares voluntarios, el cumplimiento de las NOM es obligatorio para los productos e instalaciones aplicables.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las normas NOM aplican a:</p><ul><li>Equipos e instalaciones eléctricas</li><li>Tableros de control y sistemas industriales</li><li>Productos de consumo e industriales que ingresan al mercado mexicano</li><li>Maquinaria y sistemas relacionados con la seguridad</li></ul><p>Son requeridas en:</p><ul><li>Instalaciones industriales en México</li><li>Equipos y maquinaria importados</li><li>Proyectos sujetos a inspección por autoridades locales</li></ul><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><ul><li>Las normas NOM son obligatorias por ley, no opcionales</li><li>La certificación suele ser necesaria para la aprobación e importación de productos</li><li>Las NOM pueden referenciar o alinearse con estándares internacionales</li><li>La documentación y el etiquetado deben cumplir requisitos nacionales específicos</li><li>El incumplimiento puede resultar en rechazos, multas o restricciones operativas</li></ul><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>Verifica siempre qué normas NOM aplican al proyecto o equipo</li><li>Asegura que la certificación esté completa antes de la instalación o importación</li><li>No asumas que el cumplimiento internacional satisface automáticamente las NOM</li><li>Trabaja con laboratorios certificados u organismos autorizados cuando sea necesario</li><li>La falta de cumplimiento NOM es una causa común de retrasos en proyectos en México</li></ul>',23)])])}const h=i(n,[["render",l]]);export{m as __pageData,h as default};
